def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    term1 = ((ratio - a) ** 6) / (a * b * 0.85 + 1.2)
                    term2 = np.cos(ratio * b / (a + 0.5))
                    priority += term1 * term2 * np.exp(-0.1 * b)
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 1.7
            if i % 2 == 0:
                priority += np.log(ratio * i + 1) * 2.2
            else:
                priority -= np.tan(ratio * (i + 1) * 0.4) * 1.7
        elif 4 < ratio <= 7:
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    val = ((ratio - p) ** 4) * np.sin(ratio * p * 1.1) / (q + 0.7)
                    priority += np.tanh(val) * 1.4
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 2.5
            if bin_cap > item * 5:
                priority -= np.exp(-(bin_cap/item)) * 3.5
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.1) * np.cos(r * ratio * 1.2)
                if r % 3 == 0:
                    s -= np.sin(ratio * r) * 0.1 * r
            priority = (s * np.cos(8 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
            if bin_cap < item:
                priority += np.sqrt(item / (bin_cap + 0.3)) * 3.2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 0.3) * np.sin(n * ratio * 1.5)
                if n % 4 == 1:
                    s += np.log1p(ratio * n)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.1)
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 3.7)
                if n % 2 == 0:
                    s += np.cos(n * ratio * 1.1) * 0.5
            priority = s
            if (i + int(item * 1.8)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 3.2) * np.cos(k * ratio * 2.3)
                if k % 5 == 0:
                    s -= np.sin(k * ratio) * 0.3
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
                if t % 2 == 0:
                    s += np.cos(t * ratio * 0.9) * 0.4
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 1.0)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2.5 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-2.5 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.8
        if i % 5 == 0:
            for w in range(1, 4):
                priority += np.tanh(ratio * (i + w) * 0.5) * 0.6
        else:
            for w in range(1, 4):
                priority -= np.tanh(ratio * (i + w) * 0.5) * 0.6
        priorities[i] = priority
    return priorities
